import React, { useState } from 'react'; 
import { useAuth } from '../contexts/AuthContext';
import { Card, CardContent, CardHeader, CardTitle } from '../components/ui/card';
import { Button } from '../components/ui/button';
import { Input } from '../components/ui/input';
import { Label } from '../components/ui/label';
import { Textarea } from '../components/ui/textarea';
import { Avatar, AvatarFallback, AvatarImage } from '../components/ui/avatar';
import { Badge } from '../components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '../components/ui/tabs';
import { User, Phone, MapPin, Mail, Edit, Save, X, Star, Coins, Package, TrendingUp, UserX, UserCheck, AlertTriangle } from 'lucide-react';
import { useToast } from '../hooks/use-toast';

const API_BASE = process.env.REACT_APP_BACKEND_URL + '/api';

const ProfilePage = () => {
  const { user, updateUser } = useAuth();
  const { toast } = useToast();
  const [isEditing, setIsEditing] = useState(false);
  const [loading, setLoading] = useState(false);
  const [deactivateLoading, setDeactivateLoading] = useState(false);
  const [showDeactivateConfirm, setShowDeactivateConfirm] = useState(false);
  const [formData, setFormData] = useState({
    name: user?.name || '',
    phone: user?.phone || '',
    address: user?.address || ''
  });

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleSave = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE}/users/profile`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(formData)
      });

      if (response.ok) {
        const updatedUser = await response.json();
        updateUser(updatedUser);
        setIsEditing(false);
        toast({
          title: "Profile updated",
          description: "Your profile has been updated successfully.",
        });
      } else {
        throw new Error('Failed to update profile');
      }
    } catch (error) {
      console.error('Error updating profile:', error);
      toast({
        title: "Update failed",
        description: "Failed to update profile. Please try again.",
        variant: "destructive",
      });
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    setFormData({
      name: user?.name || '',
      phone: user?.phone || '',
      address: user?.address || ''
    });
    setIsEditing(false);
  };

  const handleAccountStatusToggle = async () => {
    setDeactivateLoading(true);
    try {
      const token = localStorage.getItem('token');
      const isCurrentlyActive = user.is_active !== false; // Default to active if undefined
      const endpoint = isCurrentlyActive ? 'deactivate' : 'activate';
      const response = await fetch(`${API_BASE}/users/${endpoint}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        }
      });

      if (response.ok) {
        const updatedUser = await response.json();
        updateUser(updatedUser);
        setShowDeactivateConfirm(false);
        toast({
          title: isCurrentlyActive ? "Account deactivated" : "Account activated",
          description: isCurrentlyActive 
            ? "Your account has been deactivated. Your items will no longer be visible to other users." 
            : "Your account has been activated. Your items are now visible to other users.",
        });
      } else {
        throw new Error(`Failed to ${isCurrentlyActive ? 'deactivate' : 'activate'} account`);
      }
    } catch (error) {
      console.error('Error toggling account status:', error);
      toast({
        title: "Operation failed",
        description: `Failed to ${user.is_active !== false ? 'deactivate' : 'activate'} account. Please try again.`,
        variant: "destructive",
      });
    } finally {
      setDeactivateLoading(false);
    }
  };

  if (!user) {
    return <div>Loading...</div>;
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-4xl">
      <div className="space-y-8">
        {/* Profile Header */}
        <Card>
          <CardContent className="pt-6">
            <div className="flex flex-col md:flex-row items-start md:items-center space-y-4 md:space-y-0 md:space-x-6">
              <Avatar className="h-24 w-24">
                <AvatarImage src={user.profile_image} />
                <AvatarFallback className="text-2xl">
                  {user.name.charAt(0)}
                </AvatarFallback>
              </Avatar>
              
              <div className="flex-1">
                <div className="flex flex-col md:flex-row md:items-center md:justify-between">
                  <div>
                    <h1 className="text-3xl font-bold text-foreground">{user.name}</h1>
                    <p className="text-muted-foreground flex items-center mt-1">
                      <Mail className="h-4 w-4 mr-2" />
                      {user.email}
                    </p>
                    <div className="flex items-center space-x-4 mt-2">
                      <Badge variant="secondary" className="flex items-center space-x-1">
                        <Coins className="h-3 w-3" />
                        <span>{user.tokens} tokens</span>
                      </Badge>
                      <Badge variant="secondary" className="flex items-center space-x-1">
                        <Star className="h-3 w-3" />
                        <span>{user.stars} stars</span>
                      </Badge>
                      <Badge variant={user.is_active !== false ? "default" : "destructive"} className="flex items-center space-x-1">
                        {user.is_active !== false ? <UserCheck className="h-3 w-3" /> : <UserX className="h-3 w-3" />}
                        <span>{user.is_active !== false ? 'Active' : 'Inactive'}</span>
                      </Badge>
                    </div>
                  </div>
                  
                  <Button
                    onClick={() => setIsEditing(!isEditing)}
                    variant={isEditing ? "outline" : "default"}
                    className="mt-4 md:mt-0"
                  >
                    {isEditing ? (
                      <>
                        <X className="h-4 w-4 mr-2" />
                        Cancel
                      </>
                    ) : (
                      <>
                        <Edit className="h-4 w-4 mr-2" />
                        Edit Profile
                      </>
                    )}
                  </Button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        <Tabs defaultValue="profile" className="space-y-6">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="profile">Profile Details</TabsTrigger>
            <TabsTrigger value="stats">Statistics</TabsTrigger>
          </TabsList>

          {/* Profile Details Tab */}
          <TabsContent value="profile" className="space-y-6">
            <Card>
              <CardHeader>
                <CardTitle>Personal Information</CardTitle>
              </CardHeader>
              <CardContent className="space-y-4">
                {isEditing ? (
                  <>
                    <div className="space-y-2">
                      <Label htmlFor="name">Full Name</Label>
                      <div className="relative">
                        <User className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                        <Input
                          id="name"
                          name="name"
                          value={formData.name}
                          onChange={handleInputChange}
                          className="pl-10"
                          placeholder="Enter your full name"
                        />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="phone">Phone Number</Label>
                      <div className="relative">
                        <Phone className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                        <Input
                          id="phone"
                          name="phone"
                          value={formData.phone}
                          onChange={handleInputChange}
                          className="pl-10"
                          placeholder="Enter your phone number"
                        />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <Label htmlFor="address">Address</Label>
                      <div className="relative">
                        <MapPin className="absolute left-3 top-3 h-4 w-4 text-muted-foreground" />
                        <Textarea
                          id="address"
                          name="address"
                          value={formData.address}
                          onChange={handleInputChange}
                          className="pl-10 min-h-[100px]"
                          placeholder="Enter your complete address"
                        />
                      </div>
                    </div>

                    <div className="flex space-x-2 pt-4">
                      <Button onClick={handleSave} disabled={loading}>
                        <Save className="h-4 w-4 mr-2" />
                        {loading ? 'Saving...' : 'Save Changes'}
                      </Button>
                      <Button variant="outline" onClick={handleCancel}>
                        Cancel
                      </Button>
                    </div>
                  </>
                ) : (
                  <>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                        <Label className="text-sm font-medium text-muted-foreground">Full Name</Label>
                        <div className="flex items-center space-x-2">
                          <User className="h-4 w-4 text-muted-foreground" />
                          <span className="text-foreground">{user.name}</span>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label className="text-sm font-medium text-muted-foreground">Email</Label>
                        <div className="flex items-center space-x-2">
                          <Mail className="h-4 w-4 text-muted-foreground" />
                          <span className="text-foreground">{user.email}</span>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label className="text-sm font-medium text-muted-foreground">Phone</Label>
                        <div className="flex items-center space-x-2">
                          <Phone className="h-4 w-4 text-muted-foreground" />
                          <span className="text-foreground">{user.phone}</span>
                        </div>
                      </div>

                      <div className="space-y-2">
                        <Label className="text-sm font-medium text-muted-foreground">Member Since</Label>
                        <div className="flex items-center space-x-2">
                          <span className="text-foreground">
                            {new Date(user.created_at).toLocaleDateString()}
                          </span>
                        </div>
                      </div>
                    </div>

                    <div className="space-y-2">
                      <Label className="text-sm font-medium text-muted-foreground">Address</Label>
                      <div className="flex items-start space-x-2">
                        <MapPin className="h-4 w-4 text-muted-foreground mt-0.5" />
                        <span className="text-foreground">{user.address}</span>
                      </div>
                    </div>
                  </>
                )}
              </CardContent>
            </Card>

            {/* Account Status */}
            <Card>
              <CardHeader>
                <CardTitle>Account Status</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-6">
                  <div className="flex items-center justify-between p-4 bg-muted/50 rounded-lg">
                    <div>
                      <p className="font-medium">Verification Status</p>
                      <p className="text-sm text-muted-foreground">
                        {user.verified ? 'Verified' : 'Not verified'}
                      </p>
                    </div>
                    <Badge variant={user.verified ? "default" : "secondary"}>
                      {user.verified ? 'Verified' : 'Pending'}
                    </Badge>
                  </div>

                  <div className="flex items-center justify-between p-4 bg-muted/50 rounded-lg">
                    <div>
                      <p className="font-medium">Account Type</p>
                      <p className="text-sm text-muted-foreground">Standard Member</p>
                    </div>
                    <Badge variant="outline">Standard</Badge>
                  </div>
                </div>

                {/* Account Deactivation/Activation Section */}
                <div className="border-t pt-6">
                  <div className="flex items-start justify-between">
                    <div>
                      <h3 className="font-medium text-foreground mb-2">Account Status Management</h3>
                      <p className="text-sm text-muted-foreground mb-4">
                        {user.is_active !== false 
                          ? 'Deactivating your account will hide all your items from other users and prevent new transactions. You can reactivate anytime.'
                          : 'Your account is currently deactivated. Activate it to make your items visible to other users.'
                        }
                      </p>
                      {user.is_active === false && (
                        <div className="flex items-center space-x-2 p-3 bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800 rounded-lg mb-4">
                          <AlertTriangle className="h-4 w-4 text-orange-600 dark:text-orange-400" />
                          <span className="text-sm text-orange-800 dark:text-orange-200">
                            Your account is inactive. Items are hidden from browse.
                          </span>
                        </div>
                      )}
                    </div>
                  </div>

                  {!showDeactivateConfirm ? (
                    <Button
                      variant={user.is_active !== false ? "destructive" : "default"}
                      onClick={() => user.is_active !== false ? setShowDeactivateConfirm(true) : handleAccountStatusToggle()}
                      disabled={deactivateLoading}
                    >
                      {user.is_active !== false ? (
                        <>
                          <UserX className="h-4 w-4 mr-2" />
                          {deactivateLoading ? 'Deactivating...' : 'Deactivate Account'}
                        </>
                      ) : (
                        <>
                          <UserCheck className="h-4 w-4 mr-2" />
                          {deactivateLoading ? 'Activating...' : 'Activate Account'}
                        </>
                      )}
                    </Button>
                  ) : (
                    <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-lg">
                      <div className="flex items-start space-x-3">
                        <AlertTriangle className="h-5 w-5 text-red-600 dark:text-red-400 mt-0.5" />
                        <div className="flex-1">
                          <p className="font-medium text-red-800 dark:text-red-200">
                            Are you sure you want to deactivate your account?
                          </p>
                          <p className="text-sm text-red-700 dark:text-red-300 mt-1">
                            This will hide all your items from other users and prevent new transactions.
                          </p>
                          <div className="flex space-x-2 mt-4">
                            <Button
                              size="sm"
                              variant="destructive"
                              onClick={handleAccountStatusToggle}
                              disabled={deactivateLoading}
                            >
                              {deactivateLoading ? 'Deactivating...' : 'Yes, Deactivate'}
                            </Button>
                            <Button
                              size="sm"
                              variant="outline"
                              onClick={() => setShowDeactivateConfirm(false)}
                            >
                              Cancel
                            </Button>
                          </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          </TabsContent>

          {/* Statistics Tab */}
          <TabsContent value="stats" className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <Card>
                <CardContent className="flex items-center p-6">
                  <div className="flex items-center space-x-4">
                    <div className="p-2 bg-primary/10 rounded-full">
                      <Coins className="h-6 w-6 text-primary" />
                    </div>
                    <div>
                      <p className="text-2xl font-bold">{user.tokens}</p>
                      <p className="text-sm text-muted-foreground">Available Tokens</p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardContent className="flex items-center p-6">
                  <div className="flex items-center space-x-4">
                    <div className="p-2 bg-yellow-100 rounded-full dark:bg-yellow-900">
                      <Star className="h-6 w-6 text-yellow-600 dark:text-yellow-400" />
                    </div>
                    <div>
                      <p className="text-2xl font-bold">{user.stars}</p>
                      <p className="text-sm text-muted-foreground">Stars Earned</p>
                    </div>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardContent className="flex items-center p-6">
                  <div className="flex items-center space-x-4">
                    <div className="p-2 bg-green-100 rounded-full dark:bg-green-900">
                      <TrendingUp className="h-6 w-6 text-green-600 dark:text-green-400" />
                    </div>
                    <div>
                      <p className="text-2xl font-bold">{user.successful_transactions}</p>
                      <p className="text-sm text-muted-foreground">Successful Transactions</p>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <Card>
                <CardHeader>
                  <CardTitle>Lending Activity</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-muted-foreground">Total Items Lent</span>
                      <span className="font-medium">{user.total_lends}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-muted-foreground">Success Rate</span>
                      <span className="font-medium">
                        {user.total_lends > 0 
                          ? `${Math.round((user.successful_transactions / user.total_lends) * 100)}%`
                          : 'N/A'
                        }
                      </span>
                    </div>
                  </div>
                </CardContent>
              </Card>

              <Card>
                <CardHeader>
                  <CardTitle>Borrowing Activity</CardTitle>
                </CardHeader>
                <CardContent>
                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-muted-foreground">Total Items Borrowed</span>
                      <span className="font-medium">{user.total_borrows}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-muted-foreground">Return Rate</span>
                      <span className="font-medium">
                        {user.total_borrows > 0 
                          ? `${Math.round((user.successful_transactions / user.total_borrows) * 100)}%`
                          : 'N/A'
                        }
                      </span>
                    </div>
                  </div>
                </CardContent>
              </Card>
            </div>

            <Card>
              <CardHeader>
                <CardTitle>Reputation Summary</CardTitle>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  <div className="flex items-center justify-between">
                    <span className="text-muted-foreground">Trust Score</span>
                    <div className="flex items-center space-x-2">
                      <div className="flex">
                        {[...Array(5)].map((_, i) => (
                          <Star
                            key={i}
                            className={`h-4 w-4 ${
                              i < Math.min(user.stars, 5)
                                ? 'text-yellow-400 fill-current'
                                : 'text-gray-300'
                            }`}
                          />
                        ))}
                      </div>
                      <span className="font-medium">
                        {Math.min(user.stars, 5)}/5
                      </span>
                    </div>
                  </div>
                  
                  <div className="text-sm text-muted-foreground">
                    {user.stars >= 10 && (
                      <p className="text-green-600 dark:text-green-400 font-medium">
                        🎉 Excellent reputation! You're a trusted community member.
                      </p>
                    )}
                    {user.stars >= 5 && user.stars < 10 && (
                      <p className="text-blue-600 dark:text-blue-400 font-medium">
                        👍 Good reputation! Keep up the great work.
                      </p>
                    )}
                    {user.stars < 5 && (
                      <p className="text-muted-foreground">
                        Complete more successful transactions to build your reputation.
                      </p>
                    )}
                  </div>
                </div>
              </CardContent>
            </Card>
          </TabsContent>
        </Tabs>
      </div>
    </div>
  );
};

export default ProfilePage;
